local LxBaseMgr = require("LApp.Manager.LxBaseMgr")

---@class LxComponentMgr:LxBaseMgr
local LxComponentMgr = classX("LxComponentMgr", LxBaseMgr)

local LxAtlasAsset = require("LApp.component.res.LxAtlasAsset")
local LxMaterialAsset = require("LApp.component.res.LxMaterialAsset")
local LxFontAsset = require("LApp.component.res.LxFontAsset")

function LxComponentMgr:Initialize()
    LxBaseMgr.Initialize(self)

    self._componentTrans = FindObject("RehtGame/NodeCom").transform

    ---@type table<string, LxAtlasAsset>
    self._atlas = {}

    ---@type table<string,LxMaterialAsset>
    self._materials = {}

    ---@type table<string,LxFontAsset>
    self._fonts = {}

    self._simulateMode = false
end

function LxComponentMgr:Dispose()
    if self._isDisposed then return end
    local atlas = self._atlas
    for k,v in pairs(atlas) do
        v:Dispose()
        atlas[k] = nil
    end
    local materials = self._materials
    for k,v in pairs(materials) do
        v:Dispose()
        materials[k] = nil
    end
    local fonts = self._fonts
    for k,v in pairs(fonts) do
        v:Dispose()
        fonts[k] = nil
    end
    LxBaseMgr.Dispose(self)
end

function LxComponentMgr:DoAfterInitialize()
    self._simulateMode = LxResUtil.IsSimulateMode()
end

--为热重载Lua，清理持有的资源引用
function LxComponentMgr:ClearForHotReload()
    self:_InnerClearAllAtlas()
    self:_InnerClearAllMaterial()
    self:_InnerClearAllFont()
end

---热更lua 后热重载 调用
function LxComponentMgr:_InnerClearAllFont()
    local fonts = self._fonts
    for k,v in pairs(fonts) do
        v:Dispose()
        fonts[k] = nil
    end
    self._fonts = {}
end

---热更lua 后热重载 调用
function LxComponentMgr:_InnerClearAllMaterial()
    local materials = self._materials
    for k,v in pairs(materials) do
        v:Dispose()
        materials[k] = nil
    end
    self._materials = {}
end

---热更lua 后热重载 调用
function LxComponentMgr:_InnerClearAllAtlas()
    local atlas = self._atlas
    for k,v in pairs(atlas) do
        v:Dispose()
        atlas[k] = nil
    end
    self._atlas = {}
end


---@param path  string @ e.g. : spriteName
---@param executeOk function @ this function return bool, if access sprite return true other return false
function LxComponentMgr:RequestSprite(path, executeOk, executeObj)
    if string.isempty(path) then return end

    local abName = LxResPathUtil.GetSpriteAtlasPath(path)
    if string.isempty(abName) then return end

    local atlas = self._atlas[abName]
    if not atlas then
        atlas = LxAtlasAsset:New(abName)
        self._atlas[abName] = atlas
        atlas:EnableSimulateMode(self._simulateMode)
        atlas:LoadAtlas()
    end
    if atlas:IsLoading() then
        atlas:AddRequestCb(path, path, executeOk, executeObj)
        return
    end
    atlas:RequestSprite(path, path, executeOk, executeObj)
end

function LxComponentMgr:RecycleSprite(path)
    if string.isempty(path) then return end

    if self:IsDisposed() then
        print("RecycleSprite 调用错误， 不应该进入这里")
        return
    end

    local abName = LxResPathUtil.GetSpriteAtlasPath(path)
    local atlas = self._atlas[abName]
    if atlas then
        atlas:ReleaseSprite(path)
    end
end

function LxComponentMgr:CreateAtlas(abName)
    if string.isempty(abName) then return nil end

    local atlas = self._atlas[abName]
    if not atlas then
        atlas = LxAtlasAsset:New(abName)
        self._atlas[abName] = atlas
        atlas:EnableSimulateMode(self._simulateMode)
        atlas:LoadAtlas()
    end
    return atlas
end

function LxComponentMgr:RequestMaterial(materialPath,executeOk,executeObj)
    if string.isempty(materialPath) then return end

    local material = self._materials[materialPath]
    if not material then
        material = LxMaterialAsset:New(materialPath)
        self._materials[materialPath] = material
        material:LoadMaterial()
    end
    if material:IsLoading() then
        material:AddRequestCb(executeOk,executeObj)
        return
    end
    material:RequestMaterial(executeOk,executeObj,materialPath)
end

function LxComponentMgr:RequestFont(fontPath,executeOk,executeObj)
    if string.isempty(fontPath) then return end

    local font = self._fonts[fontPath]
    if not font then
        font = LxFontAsset:New(fontPath)
        self._fonts[fontPath] = font
        font:LoadFont()
    end
    if font:IsLoading() then
        font:AddRequestCb(executeOk,executeObj)
        return
    end
    font:RequestFont(executeOk,executeObj,fontPath)
end

function LxComponentMgr:ReleaseFont(fontPath)
    if string.isempty(fontPath) then return end
    
    local font = self._fonts[fontPath]
    if font then
        font:Release()
    end
end

local Time = Time
function LxComponentMgr:OnUpdate()
    local atlas = self._atlas
    local time = Time.realtimeSinceStartup
    for k,v in pairs(atlas) do
        if v:IsCanDispose() and v:IsReachFreeTime(time) then
            v:Dispose()
            atlas[k] = nil
        end
    end
end

return LxComponentMgr